#!/usr/bin/env node
/**
 * install-prompt-validation-dashboard — install the 10 fixture widgets
 * generated by `run-prompt-validation.js` into the running app's local
 * widget cache, then add a "Prompt Validation" workspace that lays them
 * out in a 3-column grid so you can SEE them all on one page.
 *
 * Why this exists: the fixtures live in `test/fixtures/widgets/@ai-built/
 * prompt-validation/`. That path isn't on the app's widget-discovery
 * surface — the registry only walks the user-data widgets cache. To
 * view the widgets in the app you need them copied + compiled into the
 * cache and surfaced in a workspace. This script does both, mirroring
 * what `widget:load-folder` + `workspace:save` would do at runtime,
 * but from a plain Node process so the app doesn't need to be open.
 *
 * On macOS / dev (unpackaged Electron), the paths are:
 *   Widgets cache:   ~/Library/Application Support/Electron/widgets/
 *   Workspaces:      ~/Library/Application Support/Electron/Dashboard/
 *                       @trops/dash-electron/workspaces.json
 *
 * The script is idempotent: re-running replaces the package install
 * and the workspace entry (matched by id), so the user can re-run
 * after every `run-prompt-validation.js` invocation to pick up fresh
 * AI output.
 *
 * Usage:
 *   node scripts/install-prompt-validation-dashboard.js
 *   node scripts/install-prompt-validation-dashboard.js --dry-run
 *
 * After running, restart `npm run dev` to pick up the new package +
 * workspace.
 */

const fs = require("fs");
const path = require("path");
const os = require("os");

const { SCENARIOS } = require("../src/AiAssistant/promptValidation/scenarios");

const PROJECT_ROOT = path.resolve(__dirname, "..");
const FIXTURE_ROOT = path.join(
    PROJECT_ROOT,
    "test/fixtures/widgets/@ai-built/prompt-validation"
);
const FIXTURE_WIDGETS_DIR = path.join(FIXTURE_ROOT, "widgets");
const FIXTURE_MANIFEST = path.join(FIXTURE_ROOT, "manifest.json");

// Electron's userData path on macOS. The app sets
// `productName: "Dash"` in package.json, so userData lands at
// ~/Library/Application Support/Dash/ regardless of packaged vs dev.
// (An older fallback to ~/Library/Application Support/Electron/
// exists for raw unpackaged builds without productName, but the
// running dev server uses the Dash path — see package.json.)
const PRODUCT_NAME = "Dash";
const USER_DATA_DIR = path.join(
    os.homedir(),
    "Library",
    "Application Support",
    PRODUCT_NAME
);
const WIDGETS_CACHE_DIR = path.join(USER_DATA_DIR, "widgets");
const REGISTRY_FILE = path.join(WIDGETS_CACHE_DIR, "registry.json");
const WORKSPACES_FILE = path.join(
    USER_DATA_DIR,
    "Dashboard",
    "@trops",
    "dash-electron",
    "workspaces.json"
);
// Per-app providers.json lives next to workspaces.json. We read it to
// auto-link each prompt-validation widget to a matching provider so
// the fixtures actually pull data instead of showing "no provider"
// empty states everywhere.
const PROVIDERS_FILE = path.join(
    USER_DATA_DIR,
    "Dashboard",
    "@trops",
    "dash-electron",
    "providers.json"
);

const PACKAGE_NAME = "@ai-built/prompt-validation";
const PACKAGE_INSTALL_DIR = path.join(
    WIDGETS_CACHE_DIR,
    "@ai-built",
    "prompt-validation"
);
const REGISTRY_FILE_FOR_COLLISIONS = path.join(
    WIDGETS_CACHE_DIR,
    "registry.json"
);
const GRANTS_FILE = path.join(USER_DATA_DIR, "widgetMcpGrants.json");
const WORKSPACE_ID = 9000000000001; // stable id so re-runs replace the same entry
const WORKSPACE_NAME = "Prompt Validation";
// Suffix appended to widget names that collide with another installed
// package's component name. dash-core's `MountTokenWrapper` passes
// `params.name` (the BARE widget name) to the permission gate, so two
// widgets named `GoogleDriveRecentFiles` in different packages share
// a grant key — JIT consent for the AI fixture lands under the
// published @trops/google-drive widget's identity. The collision-
// safe rename keeps the fixture name distinct at the bare-name layer
// until dash-core's identity resolver prefers the scoped id (separate
// follow-up patch).
const COLLISION_SUFFIX = "PV";

const isDryRun = process.argv.includes("--dry-run");

function log(...args) {
    console.log("[install-prompt-validation]", ...args);
}

/**
 * Walk the existing registry and return the set of bare component
 * names already in use across OTHER packages. Anything we name the
 * same as one of those is a JIT-consent collision waiting to happen.
 */
function loadCollisionSet() {
    if (!fs.existsSync(REGISTRY_FILE_FOR_COLLISIONS)) return new Set();
    let registry;
    try {
        registry = JSON.parse(
            fs.readFileSync(REGISTRY_FILE_FOR_COLLISIONS, "utf8")
        );
    } catch {
        return new Set();
    }
    const out = new Set();
    for (const entry of registry.widgets || []) {
        const [name, info] = entry;
        if (name === PACKAGE_NAME) continue;
        for (const c of info?.componentNames || []) out.add(c);
    }
    return out;
}

/**
 * Decide the on-disk name we'll install each widget under. Returns a
 * map {originalName: installedName}. Collision-safe rename only fires
 * for component names already in use by another installed package;
 * unique names install unchanged so the dashboard stays readable.
 */
function planWidgetRenames(originalNames) {
    const collisions = loadCollisionSet();
    const renames = {};
    for (const name of originalNames) {
        renames[name] = collisions.has(name)
            ? `${name}${COLLISION_SUFFIX}`
            : name;
    }
    return renames;
}

/**
 * Rewrite a single widget pair (Name.js + Name.dash.js) under the
 * renamed identifier. We touch the function/export name in the .js
 * AND the import + component reference in the .dash.js so esbuild's
 * synthetic entry resolves to the renamed export. Anything else in
 * the source is left alone — we only care about identity, not logic.
 */
function renameWidgetOnDisk(dir, oldName, newName) {
    if (oldName === newName) return;
    const oldJs = path.join(dir, `${oldName}.js`);
    const oldDash = path.join(dir, `${oldName}.dash.js`);
    const newJs = path.join(dir, `${newName}.js`);
    const newDash = path.join(dir, `${newName}.dash.js`);

    // Component source: rewrite "export default function Old" → "...New"
    // and any `import Old from "./Old"`-shaped references inside.
    if (fs.existsSync(oldJs)) {
        let src = fs.readFileSync(oldJs, "utf8");
        const reBoundary = new RegExp(`\\b${oldName}\\b`, "g");
        src = src.replace(reBoundary, newName);
        fs.writeFileSync(newJs, src);
        fs.unlinkSync(oldJs);
    }

    // Config source: rewrite the import and component reference, then
    // rename the file itself. The path string inside the import must
    // also follow ("./OldName" → "./NewName").
    if (fs.existsSync(oldDash)) {
        let src = fs.readFileSync(oldDash, "utf8");
        const reBoundary = new RegExp(`\\b${oldName}\\b`, "g");
        src = src.replace(reBoundary, newName);
        fs.writeFileSync(newDash, src);
        fs.unlinkSync(oldDash);
    }
}

function copyFixturePackage() {
    if (!fs.existsSync(FIXTURE_ROOT)) {
        throw new Error(
            `Fixture root missing — run 'node scripts/run-prompt-validation.js' first: ${FIXTURE_ROOT}`
        );
    }
    if (!fs.existsSync(FIXTURE_WIDGETS_DIR)) {
        throw new Error(`Fixture widgets/ missing: ${FIXTURE_WIDGETS_DIR}`);
    }

    if (isDryRun) {
        log(`[dry-run] would copy: ${FIXTURE_ROOT} → ${PACKAGE_INSTALL_DIR}`);
        return;
    }

    // Mirror what installFromLocalPath does: nuke the prior install,
    // copy fresh, drop any stale dist/ so the compile pass below
    // produces a clean bundle from current source.
    if (fs.existsSync(PACKAGE_INSTALL_DIR)) {
        fs.rmSync(PACKAGE_INSTALL_DIR, { recursive: true, force: true });
    }
    fs.mkdirSync(path.dirname(PACKAGE_INSTALL_DIR), { recursive: true });
    fs.cpSync(FIXTURE_ROOT, PACKAGE_INSTALL_DIR, { recursive: true });

    // The fixture root carries the runner's manifest.json + raw/ —
    // both are useful to keep alongside the fixtures for inspection
    // but the widget registry doesn't need them. Leave them in place;
    // they don't interfere with discovery.
    log(`Copied package to ${PACKAGE_INSTALL_DIR}`);
}

/**
 * Write a minimal `package.json` so dash-core's widget-permission
 * resolver (`widgetPermissions.js:resolveWidgetPackagePath`) can map
 * our dotted component ids to this on-disk package. Without it the
 * resolver returns null and the gate has no manifest to consult.
 *
 * We intentionally don't declare `dash.permissions.mcp` here — those
 * are static deny-by-default declarations; leaving the section
 * unspecified means every tool call goes through JIT consent, which
 * is what we want for a test surface where the user opts in per call.
 */
function writePackageManifest() {
    if (isDryRun) {
        log(`[dry-run] would write package.json for ${PACKAGE_NAME}`);
        return;
    }
    const pkgJsonPath = path.join(PACKAGE_INSTALL_DIR, "package.json");
    fs.writeFileSync(
        pkgJsonPath,
        JSON.stringify(
            {
                name: PACKAGE_NAME,
                version: "0.0.0",
                description:
                    "Prompt-validation fixtures generated by scripts/run-prompt-validation.js. Not for publish.",
                main: "dist/index.cjs.js",
                dash: {},
            },
            null,
            2
        ) + "\n"
    );
    log(`Wrote package.json (${pkgJsonPath})`);
}

/**
 * Apply collision-safe renames on the copied install. Returns a
 * { originalName: installedName } map so downstream stages (layout
 * builder, registry registration) use the renamed identifiers.
 */
function applyCollisionRenames() {
    if (isDryRun) {
        log("[dry-run] would scan for collisions and rename");
        return {};
    }
    const widgetsDir = path.join(PACKAGE_INSTALL_DIR, "widgets");
    if (!fs.existsSync(widgetsDir)) return {};
    const originalNames = fs
        .readdirSync(widgetsDir)
        .filter((f) => f.endsWith(".dash.js"))
        .map((f) => f.replace(/\.dash\.js$/, ""));
    const renames = planWidgetRenames(originalNames);
    const changes = Object.entries(renames).filter(([a, b]) => a !== b);
    if (changes.length === 0) {
        log("No widget-name collisions detected.");
        return renames;
    }
    for (const [oldName, newName] of changes) {
        renameWidgetOnDisk(widgetsDir, oldName, newName);
    }
    log(
        `Renamed colliding widgets: ${changes
            .map(([a, b]) => `${a} → ${b}`)
            .join(", ")}`
    );
    return renames;
}

/**
 * Remove every `@ai-built/prompt-validation.*` entry from the global
 * grants store. Re-running the installer should leave the user in a
 * clean state — without this, prior corrupt grants (from earlier
 * collision-based mis-routing) keep haunting the new install.
 *
 * Only touches our fixture keys. Grants for unrelated widgets stay
 * untouched.
 */
function purgePromptValidationGrants() {
    if (!fs.existsSync(GRANTS_FILE)) return;
    if (isDryRun) {
        log("[dry-run] would purge grants for ai-built.prompt-validation.*");
        return;
    }
    let grants;
    try {
        grants = JSON.parse(fs.readFileSync(GRANTS_FILE, "utf8"));
    } catch (err) {
        log(`Could not parse grants file (${err.message}); skipping purge.`);
        return;
    }
    const before = Object.keys(grants).length;
    for (const k of Object.keys(grants)) {
        if (k.startsWith("ai-built.prompt-validation.")) delete grants[k];
    }
    const after = Object.keys(grants).length;
    if (before !== after) {
        fs.writeFileSync(GRANTS_FILE, JSON.stringify(grants, null, 2));
        log(`Purged ${before - after} prompt-validation grant(s) from store.`);
    } else {
        log("No prompt-validation grants in store to purge.");
    }
}

async function compilePackage() {
    if (isDryRun) {
        log("[dry-run] would compile widgets via dash-core widgetCompiler");
        return;
    }
    // Lazy-require + bypass the dash-core /electron entry point so
    // this script can run in plain Node. The /electron entry pulls
    // the `electron` module at top level for IPC plumbing we don't
    // need here; the compiler itself is a pure esbuild wrapper, so
    // we load it directly from its source path. Resolution walks up
    // from the dash-electron repo since dash-core's package.json
    // doesn't list `./package.json` in its `exports` map.
    const dashCoreRoot = path.join(
        PROJECT_ROOT,
        "node_modules",
        "@trops",
        "dash-core"
    );
    const widgetCompiler = require(path.join(
        dashCoreRoot,
        "electron",
        "widgetCompiler.js"
    ));
    await widgetCompiler.compileWidget(PACKAGE_INSTALL_DIR);
    log("Compiled package bundle (dist/index.cjs.js)");
}

function readWidgetNames() {
    // Pair each {Name}.js with its {Name}.dash.js. The runner already
    // wrote both files for every scenario whose parseStatus was "both"
    // or "component-only" — we list directory contents instead of
    // relying on manifest.json so a hand-edited fixture works too.
    const widgetsDir = path.join(PACKAGE_INSTALL_DIR, "widgets");
    if (!fs.existsSync(widgetsDir)) {
        throw new Error(`Compiled widgets dir missing: ${widgetsDir}`);
    }
    const entries = fs.readdirSync(widgetsDir);
    const dashFiles = entries.filter((f) => f.endsWith(".dash.js"));
    return dashFiles.map((f) => f.replace(/\.dash\.js$/, ""));
}

function updateRegistry(widgetNames) {
    if (isDryRun) {
        log(
            `[dry-run] would register ${widgetNames.length} component(s) under ${PACKAGE_NAME}`
        );
        return;
    }

    if (!fs.existsSync(WIDGETS_CACHE_DIR)) {
        fs.mkdirSync(WIDGETS_CACHE_DIR, { recursive: true });
    }

    let registry = { lastUpdated: null, widgets: [] };
    if (fs.existsSync(REGISTRY_FILE)) {
        try {
            registry = JSON.parse(fs.readFileSync(REGISTRY_FILE, "utf8"));
        } catch (err) {
            log("Existing registry.json is malformed; rewriting from scratch.");
        }
    }

    // Entries are [widgetName, widgetEntry] tuples (Map-serialized).
    const widgets = (registry.widgets || []).filter(
        ([name]) => name !== PACKAGE_NAME
    );

    const widgetEntry = {
        name: PACKAGE_NAME,
        scope: "ai-built",
        packageId: PACKAGE_NAME,
        path: PACKAGE_INSTALL_DIR,
        registeredAt: new Date().toISOString(),
        version: "0.0.0",
        description:
            "Prompt-validation fixtures — one-shot AI output for the 10 approved scenarios. Not for publish.",
        displayName: "Prompt Validation",
        componentNames: widgetNames,
        workspace: "ai-built",
    };
    widgets.push([PACKAGE_NAME, widgetEntry]);

    const next = {
        lastUpdated: new Date().toISOString(),
        widgets,
    };
    fs.writeFileSync(REGISTRY_FILE, JSON.stringify(next, null, 2));
    log(`Registered ${widgetNames.length} component(s) in ${REGISTRY_FILE}`);
}

/**
 * Read the user's providers.json and return a name lookup keyed by
 * (type, providerClass). Returns an empty map if the file is missing
 * (a fresh install with no providers configured).
 *
 * Why both keys: a user may have multiple algolia providers — one
 * `mcp`-class (Algolia MCP server) and one `credential`-class (direct
 * REST). The widget's .dash.js pins which class it needs, so we have
 * to match BOTH or we'll auto-link to a provider whose APIs the
 * widget can't use.
 */
function loadProviderIndex() {
    if (!fs.existsSync(PROVIDERS_FILE)) return new Map();
    let providers;
    try {
        providers = JSON.parse(fs.readFileSync(PROVIDERS_FILE, "utf8"));
    } catch (err) {
        log(`providers.json unreadable (${err.message}); skipping auto-link.`);
        return new Map();
    }
    const byTypeAndClass = new Map();
    for (const [name, info] of Object.entries(providers || {})) {
        const k = `${info?.type}::${info?.providerClass}`;
        // Preserve first-match wins so subsequent re-runs auto-link
        // to the same provider even when the user adds more later.
        if (!byTypeAndClass.has(k)) byTypeAndClass.set(k, name);
    }
    return byTypeAndClass;
}

/**
 * For each widget in `widgetNames`, read its sibling .dash.js and
 * extract the first providers[] entry. Returns
 *   { [widgetName]: { type, providerClass } | null }.
 *
 * Regex-based — we deliberately don't `require()` the .dash.js because
 * it's ESM with JSX-runtime imports that don't load cleanly in plain
 * Node. The shape we need is small and stable; regex over the source
 * is robust enough for the fixtures we control.
 */
function readWidgetProviderDeclarations(widgetNames) {
    const widgetsDir = path.join(PACKAGE_INSTALL_DIR, "widgets");
    const out = {};
    for (const name of widgetNames) {
        const dashPath = path.join(widgetsDir, `${name}.dash.js`);
        if (!fs.existsSync(dashPath)) {
            out[name] = null;
            continue;
        }
        const src = fs.readFileSync(dashPath, "utf8");
        const m = src.match(
            /providers\s*:\s*\[\s*\{[^}]*type\s*:\s*["']([^"']+)["'][^}]*providerClass\s*:\s*["']([^"']+)["']/
        );
        out[name] = m ? { type: m[1], providerClass: m[2] } : null;
    }
    return out;
}

/**
 * Build the workspace layout: a top-level LayoutGridContainer with 3
 * columns × ceil(N/3) rows, each cell pointing at one widget. Mirrors
 * the shape produced by saveWorkspaceForApplication — see the existing
 * fixtures at <userData>/Dashboard/@trops/dash-electron/workspaces.json
 * for reference.
 *
 * Auto-links each widget's `selectedProviders[<type>]` to the first
 * matching provider in the user's providers.json so the fixtures pull
 * real data on first render instead of showing "no provider" empty
 * states. Widgets whose declared provider type isn't configured (e.g.
 * notion/github when the user hasn't set those up) get no link and
 * render the appropriate empty state — that's intentional.
 */
function buildWorkspace(widgetNames) {
    const cols = 3;
    const rows = Math.ceil(widgetNames.length / cols);

    const providerIndex = loadProviderIndex();
    const widgetDecls = readWidgetProviderDeclarations(widgetNames);

    const linked = [];
    const unlinked = [];
    const linkPerWidget = widgetNames.map((name) => {
        const decl = widgetDecls[name];
        if (!decl) {
            unlinked.push(`${name} (no provider declared)`);
            return null;
        }
        const k = `${decl.type}::${decl.providerClass}`;
        const providerName = providerIndex.get(k);
        if (!providerName) {
            unlinked.push(`${name} (no ${decl.type}/${decl.providerClass})`);
            return null;
        }
        linked.push(`${name} → "${providerName}"`);
        return { type: decl.type, providerName };
    });
    if (linked.length) log(`Auto-linked providers: ${linked.join(", ")}`);
    if (unlinked.length)
        log(
            `No matching provider (will show empty state): ${unlinked.join(
                ", "
            )}`
        );

    // Widget items occupy ids 2..N+1; the grid is id 1.
    const layoutItems = [
        {
            id: 1,
            order: 1,
            component: "LayoutGridContainer",
            type: "grid",
            hasChildren: 1,
            scrollable: false,
            parent: 0,
            menuId: 1,
            workspace: "layout",
            width: "w-full",
            height: "h-full",
            grid: (() => {
                const grid = { rows, cols, gap: "gap-2" };
                widgetNames.forEach((_, idx) => {
                    const row = Math.floor(idx / cols) + 1;
                    const col = (idx % cols) + 1;
                    grid[`${row}.${col}`] = { component: idx + 2, hide: false };
                });
                return grid;
            })(),
        },
        ...widgetNames.map((name, idx) => {
            const link = linkPerWidget[idx];
            return {
                id: idx + 2,
                order: idx + 1,
                component: `ai-built.prompt-validation.${name}`,
                type: "widget",
                parent: 1,
                hasChildren: 0,
                scrollable: true,
                workspace: "layout",
                // Layout-item-level selectedProviders is the first lookup
                // useWidgetProviders checks (per hooks/useWidgetProviders.js).
                // We always write the field, even when empty, so the
                // widget context is well-formed.
                selectedProviders: link
                    ? { [link.type]: link.providerName }
                    : {},
            };
        }),
    ];

    return {
        id: WORKSPACE_ID,
        name: WORKSPACE_NAME,
        type: "workspace",
        label: WORKSPACE_NAME,
        version: Date.now(),
        layout: layoutItems,
        menuId: 1,
    };
}

function updateWorkspaces(workspace) {
    if (isDryRun) {
        log(
            `[dry-run] would write workspace '${WORKSPACE_NAME}' (id=${WORKSPACE_ID}) into ${WORKSPACES_FILE}`
        );
        return;
    }

    const dir = path.dirname(WORKSPACES_FILE);
    if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
    }

    let workspaces = [];
    if (fs.existsSync(WORKSPACES_FILE)) {
        try {
            workspaces = JSON.parse(fs.readFileSync(WORKSPACES_FILE, "utf8"));
            if (!Array.isArray(workspaces)) workspaces = [];
        } catch (err) {
            log("Existing workspaces.json is malformed; replacing.");
            workspaces = [];
        }
    }

    const filtered = workspaces.filter((w) => w?.id !== WORKSPACE_ID);
    filtered.push(workspace);

    fs.writeFileSync(WORKSPACES_FILE, JSON.stringify(filtered, null, 2));
    log(`Updated ${WORKSPACES_FILE}`);
}

async function main() {
    if (!fs.existsSync(FIXTURE_MANIFEST)) {
        console.error(
            `manifest.json missing at ${FIXTURE_MANIFEST}. Run 'node scripts/run-prompt-validation.js' first.`
        );
        process.exit(1);
    }
    log(`Fixture root: ${FIXTURE_ROOT}`);
    log(`Install destination: ${PACKAGE_INSTALL_DIR}`);
    log(`Workspaces file: ${WORKSPACES_FILE}`);
    if (isDryRun) log("Dry run — no files will be written.");

    copyFixturePackage();
    // Order matters: rename BEFORE compile + manifest, because both
    // discover widgets by walking the renamed filenames on disk. The
    // grant purge runs early too so we don't accidentally re-merge
    // stale grants into the new install during a re-run.
    applyCollisionRenames();
    writePackageManifest();
    purgePromptValidationGrants();
    await compilePackage();
    const widgetNames = isDryRun
        ? SCENARIOS.map((s) =>
              s.id
                  .replace(/^\d+-/, "")
                  .split("-")
                  .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
                  .join("")
          )
        : readWidgetNames();
    log(`Component(s): ${widgetNames.join(", ")}`);
    updateRegistry(widgetNames);
    const workspace = buildWorkspace(widgetNames);
    updateWorkspaces(workspace);

    log("");
    log(
        "Done. Restart `npm run dev` and open the 'Prompt Validation' workspace."
    );
}

main().catch((err) => {
    console.error("Fatal:", err);
    process.exit(1);
});
